+    #[test]
+    fn batch_summary_counts_add_up() {
+        let results: Vec<ItemResult> = (0..50)
+            .map(|i| ItemResult {
+                index: i,
+                status: if i % 5 == 0 {
+                    ItemStatus::Skipped
+                } else if i % 3 == 0 {
+                    ItemStatus::Error
+                } else {
+                    ItemStatus::Success
+                },
+                result: None,
+                error: None,
+            })
+            .collect();
+        let summary = BatchSummary::from_results(&results);
+        assert_eq!(
+            summary.succeeded + summary.failed + summary.skipped,
+            summary.total
+        );
+        assert_eq!(summary.total, 50);
+    }
